+const RISK_TIERS = ["trivial", "lite", "full"] as const;
+type RiskTier = (typeof RISK_TIERS)[number];
+
+/** Count how many runs fell into each risk tier. The key space is the closed
+ *  RiskTier union, so this map holds at most RISK_TIERS.length (3) entries. */
+export function tallyByTier(runs: readonly { tier: RiskTier }[]): Map<RiskTier, number> {
+  const counts = new Map<RiskTier, number>();
+  for (const run of runs) {
+    counts.set(run.tier, (counts.get(run.tier) ?? 0) + 1);
+  }
+  return counts;
+}
